// Basic DFT-aware flip-flop (scan flop)
// A scan flop has an extra MUX at input:
// SE=0 → D (functional data)
// SE=1 → SI (scan input from previous flop)

module scan_dff (
  input  logic clk,
  input  logic rst_n,
  input  logic d,        // functional data
  input  logic si,       // scan in (from previous flop)
  input  logic se,       // scan enable
  output logic q,
  output logic so        // scan out (to next flop)
);
  logic d_mux;
  assign d_mux = se ? si : d;  // scan MUX
  assign so = q;               // scan out = Q

  always_ff @(posedge clk or negedge rst_n)
    if (!rst_n) q <= 0;
    else        q <= d_mux;
endmodule

// In functional mode (se=0): works like a normal DFF
// In scan mode (se=1): shifts data from SI to Q

// 4-flop scan chain walkthrough
// Flops: FF0 → FF1 → FF2 → FF3
// TDI → FF0.SI → FF1.SI → FF2.SI → FF3.SI → TDO

// STEP 1: SHIFT IN test pattern '1010'
// scan_en = 1
// Clock 1: TDI=0 → FF0=0, rest shift right
// Clock 2: TDI=1 → FF0=1, FF1=0
// Clock 3: TDI=0 → FF0=0, FF1=1, FF2=0
// Clock 4: TDI=1 → FF0=1, FF1=0, FF2=1, FF3=0
// After 4 clocks: chain = [1,0,1,0]

// STEP 2: CAPTURE (apply stimulus, observe response)
// scan_en = 0
// Clock 1: combinational logic evaluates
// Each FF captures result of its D input
// New chain = [response bits]

// STEP 3: SHIFT OUT response
// scan_en = 1
// Clock 4 times → read TDO each cycle
// Compare to expected → PASS or FAIL

// KEY INSIGHT:
// Without scan: only observe chip outputs
// With scan: observe EVERY flip-flop in design!

