// DFT-friendly clock gating cell
// Integrated Clock Gating (ICG) with scan bypass
module icg_cell (
  input  logic clk,
  input  logic en,       // functional enable
  input  logic te,       // test enable (scan bypass)
  output logic gclk      // gated clock output
);
  logic en_latch;
  // Latch: transparent when clk=0
  always_latch
    if (!clk) en_latch = en | te;  // te bypasses gate in test

  assign gclk = clk & en_latch;
endmodule

// DFT-friendly reset mux
// Allows test to control reset independently
module design_top (
  input logic clk,
  input logic rst_n,
  input logic test_rst_n,  // test reset
  input logic test_mode,
  // ...
);
  logic effective_rst_n;
  // In test mode, use test_rst_n
  assign effective_rst_n = test_mode ? test_rst_n : rst_n;
endmodule

// Original design (before scan insertion)
module my_design (input clk, rst_n, a, b, c,
                   output x, y, z);
  logic q0, q1, q2;
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin q0<=0; q1<=0; q2<=0; end
    else begin
      q0 <= a & b;
      q1 <= q0 | c;
      q2 <= q1 ^ a;
    end
  end
  assign x=q0; assign y=q1; assign z=q2;
endmodule

// After scan insertion (tool adds scan ports)
module my_design_scan (
  input  clk, rst_n, a, b, c,
  input  scan_en,  // NEW: scan enable
  input  tdi,      // NEW: test data in
  output tdo,      // NEW: test data out
  output x, y, z
);
  logic q0, q1, q2;
  logic si1, si2;  // internal scan connections

  // Chain: tdi → FF0 → FF1 → FF2 → tdo
  scan_dff ff0(.clk,.rst_n,.d(a&b), .si(tdi), .se(scan_en),.q(q0),.so(si1));
  scan_dff ff1(.clk,.rst_n,.d(q0|c),.si(si1), .se(scan_en),.q(q1),.so(si2));
  scan_dff ff2(.clk,.rst_n,.d(q1^a),.si(si2), .se(scan_en),.q(q2),.so(tdo));

  assign x=q0; assign y=q1; assign z=q2;
endmodule

