// Example: detecting SA0 on AND gate output
// Gate: Y = A & B
// SA0 on Y: Y always=0 even when A=1,B=1
//
// Test vector: A=1, B=1
//   Fault-free: Y=1
//   Faulty (SA0): Y=0
//   → detects SA0!
//
// SA1 on A of AND gate:
//   Need: set A=0, B=1 → Y should be 0
//   Faulty (A SA1): A=1, B=1 → Y=1 (wrong!)
//   Test vector: A=0, B=1, expect Y=0

// SystemVerilog fault detection testbench pattern
module tb_fault_detect;
  logic a, b, y;
  and_gate dut(.a,.b,.y);

  initial begin
    // Test SA0 on Y: apply A=1,B=1, expect Y=1
    a=1; b=1; #5;
    if (y !== 1)
      $display("SA0 on Y DETECTED: y=%b", y);
    else
      $display("No SA0 fault");

    // Test SA1 on A: apply A=0,B=1, expect Y=0
    a=0; b=1; #5;
    if (y !== 0)
      $display("SA1 on A DETECTED: y=%b", y);
  end
endmodule

// OR gate: Y = A | B
// All stuck-at faults and detecting vectors:

// Fault 1: Y SA0 (output stuck at 0)
//   Need Y=1 in fault-free: use A=1,B=0
//   Fault-free: Y=1  Faulty: Y=0  → DETECTED

// Fault 2: Y SA1 (output stuck at 1)
//   Need Y=0 in fault-free: use A=0,B=0
//   Fault-free: Y=0  Faulty: Y=1  → DETECTED

// Fault 3: A SA0 (input A stuck at 0)
//   Need A=1 to matter: use A=1,B=0
//   Fault-free: Y=1  Faulty: A=0,B=0 → Y=0  → DETECTED
//   (same vector detects Y SA0 and A SA0!)

// Fault 4: A SA1 (input A stuck at 1)
//   Need A=0 to matter: use A=0,B=0
//   Fault-free: Y=0  Faulty: A=1,B=0 → Y=1  → DETECTED

// Fault 5: B SA0: use A=0,B=1 → detects B SA0
// Fault 6: B SA1: use A=0,B=0 → detects B SA1

// Minimum test set: {A=0,B=0}, {A=1,B=0}, {A=0,B=1}
// Covers all 6 faults!

