// Lab 2: Fault Detection Test Vectors
module comb_circuit (input a,b,c, output y);
  logic w1, w2;
  assign w1 = a & b;   // AND gate
  assign w2 = b | c;   // OR gate
  assign y  = w1 ^ w2; // XOR gate
endmodule

module tb_fault_vectors;
  logic a, b, c, y;
  comb_circuit dut(.a,.b,.c,.y);

  task apply_and_check(
    input logic ta, tb, tc,
    input logic exp_y,
    input string fault_name
  );
    a=ta; b=tb; c=tc; #5;
    $display("Testing %s: a=%b b=%b c=%b → y=%b (exp=%b) %s",
      fault_name, a, b, c, y, exp_y,
      y==exp_y ? "FAULT-FREE" : "FAULT DETECTED");
  endtask

  initial begin
    // Test 1: SA0 on w1 — apply A=1,B=1,C=0
    // w1=1, w2=0, Y=1 (fault-free)
    // If w1 SA0: w1=0, w2=0, Y=0 → detectable!
    apply_and_check(1,1,0, 1, "w1_SA0");

    // Test 2: SA1 on w1 — need w1=0
    // Apply A=0,B=1,C=0: w1=0, w2=1, Y=1
    // If w1 SA1: w1=1, w2=1, Y=0 → detectable!
    apply_and_check(0,1,0, 1, "w1_SA1");

    // Test 3: SA0 on Y — need Y=1
    // Apply A=1,B=1,C=0: Y=1 fault-free
    // If Y SA0: Y=0 → detectable
    apply_and_check(1,1,0, 1, "Y_SA0");

    // Test 4: SA1 on w2 — need w2=0
    // Apply A=1,B=0,C=0: w1=0,w2=0,Y=0
    // If w2 SA1: w2=1, Y=1 → detectable!
    apply_and_check(1,0,0, 0, "w2_SA1");

    $display("All fault vectors applied");
    $finish;
  end
endmodule

