// Lab 3: Manual ATPG
module circuit_atpg (input a,b,c, output y);
  logic w1, w2;
  assign w1 = ~(a ^ b);  // XNOR
  assign w2 = b | c;     // OR
  assign y  = w1 & w2;   // AND
endmodule

module tb_atpg_manual;
  logic a, b, c, y;
  int detected = 0;
  circuit_atpg dut(.a,.b,.c,.y);

  // Task: apply vector and check if fault detectable
  task test_vector(
    input logic ta,tb,tc,
    input logic expected_y,
    input string fault_name
  );
    a=ta; b=tb; c=tc; #5;
    if (y === expected_y) begin
      $display("OK  [%s] A=%b B=%b C=%b Y=%b",
               fault_name,a,b,c,y);
      detected++;
    end else
      $display("ERR [%s] Got Y=%b, exp=%b",fault_name,y,expected_y);
  endtask

  initial begin
    // w1 = XNOR(A,B): w1=1 when A==B, w1=0 when A!=B
    // w2 = OR(B,C):   w2=0 only when B=0,C=0
    // Y  = AND(w1,w2)

    // Detect w1 SA0: need w1=1 → A=B, use A=1,B=1,C=1
    // w1=1,w2=1,Y=1 fault-free
    test_vector(1,1,1, 1, "w1_SA0");

    // Detect w1 SA1: need w1=0 → A!=B, use A=0,B=1,C=1
    // w1=0,w2=1,Y=0 fault-free
    test_vector(0,1,1, 0, "w1_SA1");

    // Detect w2 SA0: need w2=1 AND w1=1
    // Use A=1,B=1,C=1: w2=1,w1=1,Y=1
    test_vector(1,1,1, 1, "w2_SA0");

    // Detect w2 SA1: need w2=0 → B=0,C=0, keep w1=1 (A=0,B=0)
    // w1=1,w2=0,Y=0 fault-free
    test_vector(0,0,0, 0, "w2_SA1");

    // Detect Y SA0: need Y=1 fault-free
    test_vector(1,1,1, 1, "Y_SA0");

    // Detect Y SA1: need Y=0 fault-free
    test_vector(0,1,1, 0, "Y_SA1");

    $display("Faults detected: %0d/6", detected);
    $finish;
  end
endmodule

