// MBIST Controller State Machine (simplified)
typedef enum logic [2:0] {
  IDLE    = 3'b000,
  MARCH0  = 3'b001,  // Write 0 to all
  MARCH1  = 3'b010,  // Read 0, Write 1 ascending
  MARCH2  = 3'b011,  // Read 1, Write 0 ascending
  MARCH3  = 3'b100,  // Read 0, Write 1 descending
  MARCH4  = 3'b101,  // Read 1, Write 0 descending
  MARCH5  = 3'b110,  // Read 0 from all
  PASS    = 3'b111
} march_state_t;

module mbist_ctrl #(parameter DEPTH=256, AW=8) (
  input  logic clk, rst_n,
  input  logic bist_en,       // start BIST
  output logic bist_done,
  output logic bist_pass,
  // Memory interface
  output logic [AW-1:0] mem_addr,
  output logic          mem_we,
  output logic          mem_wdata,
  input  logic          mem_rdata
);
  march_state_t state, next;
  logic [AW-1:0] addr_cnt;
  logic fail_flag;
  // ... state machine logic
endmodule

// March C- on 4-cell memory
// Memory state shown after each march element
// Initial: [X, X, X, X] (unknown)

// M0: ↕W0 — write 0 to all addresses
// addr=0: W0; addr=1: W0; addr=2: W0; addr=3: W0
// Memory: [0, 0, 0, 0]

// M1: ↑R0W1 — ascending, read 0 then write 1
// addr=0: R→0(OK), W1;  addr=1: R→0(OK), W1
// addr=2: R→0(OK), W1;  addr=3: R→0(OK), W1
// Memory: [1, 1, 1, 1]
// If any read returns 1 instead of 0 → SA1 detected!

// M2: ↑R1W0 — ascending, read 1 then write 0
// addr=0: R→1(OK), W0;  ... all reads must be 1
// Memory: [0, 0, 0, 0]
// SA0 on any cell detected here!

// M3: ↓R0W1 — descending order
// addr=3: R→0(OK), W1; addr=2: R→0, W1; ...
// Memory: [1, 1, 1, 1]

// M4: ↓R1W0 — descending order
// Memory: [0, 0, 0, 0]

// M5: ↕R0 — read all, expect 0
// All reads must be 0 → PASS
// Any read=1 → FAIL (stuck-at-1 fault)

$display("March C- PASSED — memory is fault-free");

