// Lab 4: Simplified MBIST Controller
module mbist_simple #(parameter DEPTH=8, AW=3) (
  input  logic clk, rst_n,
  input  logic bist_en,
  output logic bist_done,
  output logic bist_pass,
  output logic [AW-1:0] mem_addr,
  output logic          mem_we,
  output logic          mem_wdata,
  input  logic          mem_rdata
);
  typedef enum logic [1:0] {
    IDLE=0, M0_WRITE0=1, M1_RD0_WR1=2, M2_READ1=3
  } state_t;

  state_t state;
  logic [AW-1:0] addr;
  logic fail;

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      state<=IDLE; addr<=0; fail<=0;
      bist_done<=0; bist_pass<=0;
      mem_we<=0; mem_wdata<=0; mem_addr<=0;
    end else begin
      case (state)
        IDLE: begin
          if (bist_en) begin
            state <= M0_WRITE0;
            addr  <= 0; fail <= 0;
            bist_done <= 0;
          end
        end

        M0_WRITE0: begin
          // Write 0 to all addresses
          mem_addr  <= addr;
          mem_we    <= 1;
          mem_wdata <= 0;
          if (addr == DEPTH-1) begin
            state <= M1_RD0_WR1;
            addr  <= 0;
          end else addr <= addr + 1;
        end

        M1_RD0_WR1: begin
          // Read expect 0, then write 1
          mem_addr  <= addr;
          mem_we    <= 0; // read first
          // Check read data
          if (mem_rdata !== 1'b0) fail <= 1;
          // Then write 1 next cycle
          // (simplified: write 1 same cycle)
          mem_we    <= 1;
          mem_wdata <= 1;
          if (addr == DEPTH-1) begin
            state <= M2_READ1;
            addr  <= 0;
          end else addr <= addr + 1;
        end

        M2_READ1: begin
          // Read expect 1
          mem_addr <= addr;
          mem_we   <= 0;
          if (mem_rdata !== 1'b1) fail <= 1;
          if (addr == DEPTH-1) begin
            bist_done <= 1;
            bist_pass <= ~fail;
            state <= IDLE;
          end else addr <= addr + 1;
        end
      endcase
    end
  end
endmodule

// Simple 8-cell memory model
module mem8 (input clk, we, input [2:0] addr, input wdata, output logic rdata);
  logic [7:0] mem;
  always_ff @(posedge clk)
    if (we) mem[addr] <= wdata;
  assign rdata = mem[addr];
endmodule

// Testbench
module tb_mbist;
  logic clk=0, rst_n, bist_en, bist_done, bist_pass;
  logic [2:0] mem_addr;
  logic mem_we, mem_wdata, mem_rdata;

  mbist_simple dut(.clk,.rst_n,.bist_en,.bist_done,.bist_pass,
                   .mem_addr,.mem_we,.mem_wdata,.mem_rdata);
  mem8 memory(.clk,.we(mem_we),.addr(mem_addr),
               .wdata(mem_wdata),.rdata(mem_rdata));
  always #5 clk = ~clk;

  initial begin
    rst_n=0; bist_en=0;
    repeat(2) @(posedge clk); rst_n=1;
    @(posedge clk); bist_en=1;
    @(posedge clk); bist_en=0;
    // Wait for BIST to complete
    wait(bist_done==1);
    #1;
    $display("MBIST %s", bist_pass ? "PASSED" : "FAILED");
    assert(bist_pass==1) else $error("BIST should pass on good memory");
    $finish;
  end
endmodule

