// 4-bit LFSR (polynomial: x^4 + x^3 + 1)
// Taps at positions 4 and 3
module lfsr4 (
  input  logic clk, rst_n, en,
  output logic [3:0] out
);
  logic [3:0] lfsr_reg;
  logic feedback;

  assign feedback = lfsr_reg[3] ^ lfsr_reg[2]; // taps 4,3
  assign out = lfsr_reg;

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) lfsr_reg <= 4'b1001; // non-zero seed
    else if (en)
      lfsr_reg <= {lfsr_reg[2:0], feedback}; // shift left
  end
endmodule

// 4-bit MISR (signature analyzer)
// Compresses CUT responses into a signature
module misr4 (
  input  logic clk, rst_n, en,
  input  logic [3:0] data_in,  // from CUT output
  output logic [3:0] signature
);
  logic [3:0] misr_reg;
  logic feedback;

  assign feedback  = misr_reg[3] ^ misr_reg[2];
  assign signature = misr_reg;

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) misr_reg <= 4'b0000;
    else if (en)
      // Shift with XOR of incoming data
      misr_reg <= {misr_reg[2:0], feedback} ^ data_in;
  end
endmodule

// 4-bit LFSR sequence (taps at 4,3)
// Seed: 4'b1001
// Feedback = bit[3] ^ bit[2]

// Cycle 1: 1001, fb = 1^0 = 1 → next = {0,0,1,1} = 0011
// Cycle 2: 0011, fb = 0^0 = 0 → next = {0,1,1,0} = 0110
// Cycle 3: 0110, fb = 0^1 = 1 → next = {1,1,0,1} = 1101
// Cycle 4: 1101, fb = 1^1 = 0 → next = {1,0,1,0} = 1010
// Patterns: 1001, 0011, 0110, 1101

// Assume CUT responses (fault-free):
// Pattern 1: response = 0110
// Pattern 2: response = 1010
// Pattern 3: response = 0001
// Pattern 4: response = 1100

// MISR computation:
// Init: 0000
// After resp 0110: shift+XOR → some value
// After resp 1010: accumulates
// After resp 0001: accumulates
// After resp 1100: FINAL SIGNATURE = golden

// Store golden signature in ROM or hardcode in comparator
// At end of LBIST: compare MISR output to golden
// Match → PASS, Mismatch → FAIL (fault detected)
$display("LBIST complete: signature = %h", misr_out);
if (misr_out == GOLDEN_SIG) $display("LBIST PASS");
else $display("LBIST FAIL — defect detected");

