// Lab 6: Simplified TAP Controller
module tap_ctrl (
  input  logic tck, tms, tdi, trst_n,
  output logic tdo,
  output logic shift_dr, update_dr, capture_dr
);
  typedef enum logic [2:0] {
    TEST_RESET = 3'd0,
    RUN_IDLE   = 3'd1,
    SELECT_DR  = 3'd2,
    CAPTURE_DR = 3'd3,
    SHIFT_DR   = 3'd4,
    UPDATE_DR  = 3'd5
  } tap_state_t;

  tap_state_t state, next_state;

  // State register
  always_ff @(posedge tck or negedge trst_n) begin
    if (!trst_n) state <= TEST_RESET;
    else         state <= next_state;
  end

  // Next state logic
  always_comb begin
    case (state)
      TEST_RESET: next_state = tms ? TEST_RESET : RUN_IDLE;
      RUN_IDLE:   next_state = tms ? SELECT_DR  : RUN_IDLE;
      SELECT_DR:  next_state = tms ? TEST_RESET : CAPTURE_DR;
      CAPTURE_DR: next_state = tms ? UPDATE_DR  : SHIFT_DR;
      SHIFT_DR:   next_state = tms ? UPDATE_DR  : SHIFT_DR;
      UPDATE_DR:  next_state = tms ? SELECT_DR  : RUN_IDLE;
      default:    next_state = TEST_RESET;
    endcase
  end

  // Output signals
  assign shift_dr   = (state == SHIFT_DR);
  assign capture_dr = (state == CAPTURE_DR);
  assign update_dr  = (state == UPDATE_DR);
  assign tdo        = tdi; // bypass mode

endmodule

module tb_tap;
  logic tck=0, tms, tdi=0, trst_n;
  logic tdo, shift_dr, update_dr, capture_dr;

  tap_ctrl dut(.*);
  always #5 tck = ~tck;

  task send_tms(input logic t);
    tms = t; @(posedge tck); #1;
  endtask

  initial begin
    trst_n=0; tms=1;
    @(posedge tck); trst_n=1;

    // Navigate: RESET→IDLE→SELECT_DR→CAPTURE_DR→SHIFT_DR
    send_tms(0); // → RUN_IDLE
    send_tms(1); // → SELECT_DR
    assert(shift_dr==0 && capture_dr==0)
      else $error("Should be in SELECT_DR");
    send_tms(0); // → CAPTURE_DR
    assert(capture_dr==1)
      else $error("Should be in CAPTURE_DR");
    send_tms(0); // → SHIFT_DR
    assert(shift_dr==1)
      else $error("Should be in SHIFT_DR");

    // Stay in SHIFT_DR for 4 cycles (TMS=0)
    repeat(4) send_tms(0);
    assert(shift_dr==1) else $error("Should stay in SHIFT_DR");

    // Exit: TMS=1 → UPDATE_DR
    send_tms(1);
    assert(update_dr==1) else $error("Should be in UPDATE_DR");

    $display("TAP controller PASSED");
    $finish;
  end
endmodule

