// 2 external channels → 4 internal scan chain inputs
// Encoding matrix defines which channels XOR to each output
module decompressor_2to4 (
  input  logic [1:0] ext_in,   // 2 ATE channels
  output logic [3:0] chain_in  // 4 internal chains
);
  // Each chain_in = XOR of specific ext_in bits
  // Encoding matrix (H):
  // chain0 = ext0 ^ ext1
  // chain1 = ext0
  // chain2 = ext1
  // chain3 = ext0 ^ ext1  (same as chain0 — OK for compression)
  assign chain_in[0] = ext_in[0] ^ ext_in[1];
  assign chain_in[1] = ext_in[0];
  assign chain_in[2] = ext_in[1];
  assign chain_in[3] = ext_in[0] ^ ext_in[1];
