// At-speed test clock controller
// Generates: slow scan clock and fast capture pulses
module atspeed_clk_ctrl (
  input  logic clk_func,    // functional clock (fast)
  input  logic clk_scan,    // scan clock (slow, from ATE)
  input  logic scan_en,     // scan enable
  input  logic test_mode,
  input  logic capture_en,  // enable capture phase
  output logic clk_out      // to flip-flops
);
  // During shift: use slow scan clock
  // During capture: use one/two functional clock pulses
  assign clk_out = test_mode ?
                   (scan_en ? clk_scan :    // shift phase
                              clk_func)     // capture phase
                   : clk_func;              // functional
endmodule

// LOC (Launch-on-Capture) sequence:
// 1. Shift in pattern (scan_en=1, slow clock)
// 2. Pulse 1: scan_en=0, apply clk_func pulse 1 (LAUNCH)
//    → FF outputs transition based on combinational logic
// 3. Pulse 2: apply clk_func pulse 2 (CAPTURE at speed)
//    → Capture result — detects if path met timing
// 4. Shift out result (scan_en=1, slow clock)

// LOC At-Speed Test Timeline
// Target: detect SA-slow on critical path
// FF_A → [combinational cloud] → FF_B

// PHASE 1: SHIFT (slow clock, SE=1)
// Shift pattern into FF_A: Q_A = 0
// (setting up initial state for launch)
// Shift count = chain length cycles

// PHASE 2: LAUNCH (SE=0, functional clock pulse 1)
// FF_A.D = 1 (from combinational logic with previous state)
// Rising edge of fast clock → FF_A.Q transitions 0→1
// Combinational logic starts evaluating immediately
// If path is SLOW: FF_B.D arrives late (after setup window)

// PHASE 3: CAPTURE (SE=0, functional clock pulse 2)
// Rising edge arrives ONE FULL PERIOD after launch
// If path is fault-free: FF_B.Q = correct value
// If path has resistive open: FF_B.Q = wrong value!
// → TRANSITION FAULT DETECTED

// PHASE 4: SHIFT OUT (slow clock, SE=1)
// Shift out captured values from all FFs
// Compare to expected pattern on ATE
// Any mismatch → at-speed defect reported

$display("At-speed capture complete");
$display("Checking FF_B value after capture...");

