// Lab 8: At-Speed LOC Clock Controller
module atspeed_ctrl (
  input  logic clk_fast, clk_slow,
  input  logic scan_en, test_mode, loc_en,
  output logic clk_dff,
  output logic capture_done
);
  logic [1:0] pulse_count;
  logic counting;

  // Clock mux
  always_comb begin
    if (!test_mode)
      clk_dff = clk_fast;         // functional mode
    else if (scan_en)
      clk_dff = clk_slow;         // scan shift mode
    else if (loc_en)
      clk_dff = clk_fast;         // LOC capture
    else
      clk_dff = 1'b0;             // hold
  end

  // LOC pulse counter — count 2 fast clock pulses
  always_ff @(posedge clk_fast or negedge loc_en) begin
    if (!loc_en) begin
      pulse_count  <= 0;
      capture_done <= 0;
    end else if (test_mode && !scan_en && loc_en) begin
      if (pulse_count < 2)
        pulse_count <= pulse_count + 1;
      if (pulse_count == 1)  // after 2nd pulse
        capture_done <= 1;
    end
  end

endmodule

module tb_atspeed;
