// Simple 8-flop scan chain DUT
module dut_chip (
  input  logic clk, rst_n,
  input  logic scan_en, tdi,
  input  logic [3:0] pi,
  output logic [1:0] po,
  output logic tdo
);
  logic [7:0] scan_chain;
  logic [7:0] d_func;

  // Functional data: mix of primary inputs and previous state
  assign d_func[7:4] = pi ^ scan_chain[3:0];
  assign d_func[3:0] = scan_chain[7:4] & pi;

  // Scan chain with functional mux
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) scan_chain <= 8'h00;
    else if (scan_en)
      scan_chain <= {scan_chain[6:0], tdi}; // shift
    else
      scan_chain <= d_func;  // capture
  end

  assign tdo = scan_chain[7];    // TDO = last flop
  assign po  = scan_chain[7:6]; // primary outputs
endmodule

module tb_ate_sim;
  logic clk=0, rst_n, scan_en, tdi;
  logic [3:0] pi;
  logic [1:0] po;
  logic tdo;
  int pass_count=0, total_patterns=0;

  dut_chip dut(.*);
  always #5 clk = ~clk;

  // Task: apply one ATPG pattern
  task apply_pattern(
    input logic [7:0] shift_in,
    input logic [3:0] pri_in,
    input logic [7:0] expected_out,
    input string      pat_name
  );
    logic [7:0] shifted_out;
    // Phase 1: Shift in
    scan_en = 1; pi = pri_in;
    for (int i=7; i>=0; i--) begin
      tdi = shift_in[i];
      @(posedge clk);
    end
    // Phase 2: Capture
    scan_en = 0;
    @(posedge clk);
    // Phase 3: Shift out
    scan_en = 1;
    for (int i=7; i>=0; i--) begin
      @(posedge clk); #1;
      shifted_out[i] = tdo;
    end
    total_patterns++;
    if (shifted_out == expected_out) begin
      $display("PASS [%s]: shifted_out=%b", pat_name, shifted_out);
      pass_count++;
    end else
      $display("FAIL [%s]: got=%b exp=%b",
               pat_name, shifted_out, expected_out);
  endtask

  initial begin
    rst_n=0; scan_en=0; tdi=0; pi=0;
    repeat(2) @(posedge clk); rst_n=1;

    // Pattern 1: shift in 10110100
    apply_pattern(8'b10110100, 4'b1010, 8'bxxxxxxxx, "PAT1");

    // Pattern 2: shift in 01001011
    apply_pattern(8'b01001011, 4'b0101, 8'bxxxxxxxx, "PAT2");

    $display("ATE Results: %0d/%0d patterns passed",
             pass_count, total_patterns);
    $finish;
  end
endmodule

