// Lab 11: Classic DFT Interview Challenge
module scan_dff (
  input  logic clk, rst_n, d, si, se,
  output logic q, so
);
  assign so = q;
  always_ff @(posedge clk or negedge rst_n)
    if (!rst_n) q <= 0;
    else        q <= se ? si : d;
endmodule

module dut_4bit (
  input  logic clk, rst_n,
  input  logic [3:0] d,
  input  logic scan_en, tdi,
  output logic [3:0] q,
  output logic parity,
  output logic tdo
);
  logic so0, so1, so2;

  // Chain: tdi → ff0 → ff1 → ff2 → ff3 → tdo
  scan_dff ff0(.clk,.rst_n,.d(d[0]),.si(tdi), .se(scan_en),.q(q[0]),.so(so0));
  scan_dff ff1(.clk,.rst_n,.d(d[1]),.si(so0), .se(scan_en),.q(q[1]),.so(so1));
  scan_dff ff2(.clk,.rst_n,.d(d[2]),.si(so1), .se(scan_en),.q(q[2]),.so(so2));
  scan_dff ff3(.clk,.rst_n,.d(d[3]),.si(so2), .se(scan_en),.q(q[3]),.so(tdo));

  assign parity = ^q;  // XOR all bits
endmodule

module tb_dft_interview;
  logic clk=0, rst_n, scan_en, tdi, tdo;
  logic [3:0] d, q;
  logic parity;
  int pass=0, fail=0;

  dut_4bit dut(.*);
  always #5 clk = ~clk;

  // Task: shift in 4-bit pattern (LSB first into ff0)
  task shift_in(input logic [3:0] pattern);
    scan_en=1;
    for (int i=0; i<4; i++) begin
      tdi = pattern[i];
      @(posedge clk);
    end
  endtask

  // Task: capture (1 functional clock)
  task capture;
    scan_en=0; d=4'b0000;
    @(posedge clk); #1;
  endtask

  // Task: check parity
  task check_parity(
    input logic exp_parity,
    input string test_name
  );
    if (parity === exp_parity) begin
      $display("PASS [%s]: q=%b parity=%b", test_name, q, parity);
      pass++;
    end else begin
      $display("FAIL [%s]: q=%b parity=%b exp=%b",
               test_name, q, parity, exp_parity);
      fail++;
    end
  endtask

  initial begin
    rst_n=0; scan_en=0; tdi=0; d=0;
    repeat(2) @(posedge clk); rst_n=1;

    // Test 1: shift 1010, parity = 1^0^1^0 = 0
    shift_in(4'b0101); // LSB first: 0→ff0,1→ff1,0→ff2,1→ff3
    capture;
    check_parity(0, "1010_parity");

    // Test 2: shift 1111, parity = 0
    shift_in(4'b1111);
    capture;
    check_parity(0, "1111_parity");

    // Test 3: shift 1110, parity = 1
    shift_in(4'b0111);
    capture;
    check_parity(1, "1110_parity");

    $display("DFT Interview: %0d PASS, %0d FAIL", pass, fail);
    if (fail==0) $display("** INTERVIEW PASSED **");
    else         $display("** INTERVIEW FAILED **");
    $finish;
  end
endmodule

// Lab 12: FINAL BOSS — Complete DFT System
import std::*;

// Scan flip-flop
module scan_dff (input clk,rst_n,d,si,se, output logic q,so);
  assign so=q;
  always_ff @(posedge clk or negedge rst_n)
    if(!rst_n) q<=0; else q<= se?si:d;
endmodule

// 4-cell SRAM
module sram4 (input clk,we,input[1:0]addr,input din, output logic dout);
  logic[3:0] mem;
  always_ff @(posedge clk) if(we) mem[addr]<=din;
  assign dout=mem[addr];
endmodule

// Main SoC DFT module
module soc_dft (
  input  logic clk, rst_n,
  input  logic [3:0] instr,
  output logic [3:0] result,
  input  logic tck, tms, tdi_jtag, trst_n,
  output logic tdo_jtag,
  input  logic scan_en, tdi_scan,
  output logic tdo_scan,
  input  logic bist_en,
  output logic bist_done, bist_pass
);
  // ── Scan chain (4 flops) ──
  logic [3:0] q;
  logic so0,so1,so2;
  scan_dff ff0(.clk,.rst_n,.d(instr[0]),.si(tdi_scan),.se(scan_en),.q(q[0]),.so(so0));
  scan_dff ff1(.clk,.rst_n,.d(instr[1]),.si(so0),    .se(scan_en),.q(q[1]),.so(so1));
  scan_dff ff2(.clk,.rst_n,.d(instr[2]),.si(so1),    .se(scan_en),.q(q[2]),.so(so2));
  scan_dff ff3(.clk,.rst_n,.d(instr[3]),.si(so2),    .se(scan_en),.q(q[3]),.so(tdo_scan));
  assign result = q;

  // ── Simplified JTAG (IDCODE only) ──
  logic [31:0] idcode = 32'hDEAD_BEEF;
  logic [31:0] id_shift;
  logic [4:0]  tap_state;
  logic shift_active;

  // TAP: reset on trst_n or 5x TMS=1
  // Simplified: just provide IDCODE shift
  always_ff @(posedge tck or negedge trst_n) begin
    if (!trst_n) begin
      id_shift <= idcode;
    end else if (tms) begin
      id_shift <= idcode; // reset-like
    end else begin
      id_shift <= {tdi_jtag, id_shift[31:1]}; // shift right
    end
  end
  assign tdo_jtag = id_shift[0]; // LSB out

  // ── MBIST (4-cell memory) ──
  logic mem_we;
  logic [1:0] mem_addr;
  logic mem_din, mem_dout;
  logic [1:0] bist_state;
  logic fail_flag;

  sram4 mem(.clk,.we(mem_we),.addr(mem_addr),.din(mem_din),.dout(mem_dout));

  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      bist_state<=0; bist_done<=0; bist_pass<=0;
      mem_we<=0; mem_addr<=0; mem_din<=0; fail_flag<=0;
    end else begin
      case (bist_state)
        2'd0: if (bist_en) begin // M0: write 0
                mem_we<=1; mem_din<=0; mem_addr<=0;
                bist_state<=1;
              end
        2'd1: begin // M1: read 0 write 1
                mem_we<=0;
                if (mem_dout!==0) fail_flag<=1;
                mem_we<=1; mem_din<=1;
                if (mem_addr==3) begin mem_addr<=0; bist_state<=2; end
                else mem_addr<=mem_addr+1;
              end
        2'd2: begin // M2: read 1
                mem_we<=0;
                if (mem_dout!==1) fail_flag<=1;
                if (mem_addr==3) begin
                  bist_done<=1; bist_pass<=~fail_flag;
                  bist_state<=0;
                end else mem_addr<=mem_addr+1;
              end
        default: bist_state<=0;
      endcase
    end
  end
endmodule

// FINAL BOSS TESTBENCH
module tb_soc_dft_final;
  logic clk=0, rst_n;
  logic [3:0] instr, result;
  logic tck=0, tms, tdi_jtag, trst_n;
  logic tdo_jtag;
  logic scan_en, tdi_scan, tdo_scan;
  logic bist_en, bist_done, bist_pass;

  soc_dft dut(.*);
  always #5 clk=~clk;
  always #8 tck=~tck;

  // Read IDCODE via JTAG
  task jtag_read_idcode;
    logic [31:0] idcode;
    trst_n=0; @(posedge tck); trst_n=1;
    // Shift out 32 bits with TMS=0
    tms=0;
    for (int i=0; i<32; i++) begin
      @(posedge tck); #1;
      idcode[i] = tdo_jtag;
    end
    $display("JTAG IDCODE: %h (expected DEAD_BEEF)", idcode);
    assert(idcode==32'hDEAD_BEEF)
      else $error("IDCODE MISMATCH!");
  endtask

  // Run MBIST
  task run_mbist;
    bist_en=1; @(posedge clk); bist_en=0;
    wait(bist_done==1); #1;
    $display("MBIST: %s", bist_pass ? "PASS" : "FAIL");
    assert(bist_pass) else $error("MBIST FAILED");
  endtask

  // Scan test
  task scan_test;
    // Shift in 1010 (LSB first)
    scan_en=1;
    tdi_scan=0; @(posedge clk);
    tdi_scan=1; @(posedge clk);
    tdi_scan=0; @(posedge clk);
    tdi_scan=1; @(posedge clk);
    // Capture
    scan_en=0; instr=4'b0000;
    @(posedge clk); #1;
    $display("Scan capture: result=%b", result);
    assert(result==4'b1010)
      else $error("Scan FAIL: result=%b",result);
    $display("Scan test: PASS");
  endtask

  initial begin
    rst_n=0; trst_n=0; bist_en=0; scan_en=0;
    tdi_jtag=0; tdi_scan=0; tms=1; instr=0;
    repeat(2) @(posedge clk); rst_n=1; trst_n=1;

    $display("== FINAL BOSS: Complete SoC DFT Test ==");

    // 1. JTAG IDCODE
    $display("--- Test 1: JTAG IDCODE ---");
    jtag_read_idcode;

    // 2. MBIST
    $display("--- Test 2: MBIST ---");
    run_mbist;

    // 3. Scan
    $display("--- Test 3: Scan Chain ---");
    scan_test;

    $display("== ALL DFT TESTS PASSED ==");
    $finish;
  end
endmodule
